    m, n = len(s1), len(s2)
    dp = [[0] * (n + 1) for _ in range(m + 1)]
    max_score = 0
    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if s1[i-1] == s2[j-1]:
                score = dp[i-1][j-1] + 2
            elif i > 0 and j > 0:
                score = max(dp[i-1][j] - 1, dp[i][j-1] - 1)
            else:
                score = 0
            dp[i][j] = max(dp[i-1][j], dp[i][j-1], score)
            if dp[i][j] > max_score:
                max_score = dp[i][j]
    return max_score
