def parse_packet(data):
    try:
        # Validate header, extract command, verify payload length, and check checksum
        if len(data) < 4:
            return None
        header = data[0:4]
        command = header[1]
        payload_length = header[2]
        payload = data[4:4+payload_length]
        checksum = data[-1]
        calculated_checksum = sum(payload) % 256
        if calculated_checksum != checksum:
            return None
        return {'command': command, 'payload': payload}
    except Exception:
