def detect_flakiness(func, n_runs=10):
    results = []
    for _ in range(n_runs):
        try:
            result = func()
            # Convert to comparable tuple by casting types to string representation
            results.append(('success', str(result), type(result).__name__))
        except Exception:
            results.append(('exception', 'exception', type(func).__name__))

    # Group results by value and type
    unique_responses = set({r[1] for r in results if r[0] == 'success'})

    if not unique_responses:
        return False
    if len(unique_responses) == 1:
        return False
    return True
