    # Group results by value and type
    unique_values = set(results)

    if not unique_values:
        return False

    # Check if all results are the same
    if len(unique_values) == 1:
        return False

    # Check if exceptions are the only result
    if "exception" in unique_values and len(unique_values) == 1:
        return False

    # Check if exceptions are the majority
